import { BillboardText, colors, Ellipsis, ListItem, Checkbox } from '@fs/zion-ui'
import {
  ContentReply,
  HelpAskQuestion,
  LogoFamilysearch,
  LogoRootstech,
  MenuMore,
  NoticeMute,
  PersonGroup,
  ThingPresentation,
} from '@fs/zion-icon'
import { css } from '@linaria/core'
import { useParams } from '@fs/zion-router'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useTranslation } from 'react-i18next'
import { getStreamChannelAvatar } from '../../chat-avatar/chatAvatar'
import { useChatState } from '../../providers/ChatStateProvider'
import {
  CHAT_MESSAGE_TYPE,
  cidMatchesChannel,
  getChannelName,
  getChannelUnreadCount,
  isChannelMuted,
  getMessageText,
  isUserBlocked,
} from '../../helpers/stream/streamChatHelper'
import {
  isPublicChannel,
  isVendorChannel,
  isSupportChannel,
  isSessionChannel,
  isRootsTechChannel,
  isDirectChannel,
  getChatGroupParticipantCountDescription,
  isHelperConnectChannel,
} from '../../services/fsChat/fsChatService'
import formatChatTimestamp from '../../helpers/formatChatTimestamp'
import {
  useChatMultiSelectDispatch,
  useChatMultiSelectState,
  actionTypes,
} from '../../providers/ChatMultiSelectProvider'
import useChatFlags from '../../hooks/useChatFlags'

const listItemUnreadDotCss = css`
  position: relative;

  &::before {
    content: '';
    position: absolute;
    top: 50%;
    inset-inline-start: -20px;
    transform: translateY(-50%);
    width: 8px;
    height: 8px;
    background-color: ${colors.blue60};
    border-radius: 50%;
  }
`

const listItemResetCss = css`
  list-style: none;
  margin: 0;
  padding: 0;
`

function ListItemWrapper(props) {
  return <li className={listItemResetCss} {...props} />
}

function SecondaryText({ lastMessage, participantCount }) {
  return (
    <>
      <div>
        <Ellipsis>{lastMessage || ''}</Ellipsis>
      </div>
      <div>
        <Ellipsis>{participantCount}</Ellipsis>
      </div>
    </>
  )
}

const AUAIconButton = () => <HelpAskQuestion color={colors.blue30} />

function getLastDisplayMessageForChannel({ channel, client, t, isThread }) {
  let messages = []
  if (isThread) {
    messages = channel?.state?.getLatestValue()?.replies || []
  } else {
    const messageSets = channel?.state?.messageSets || []
    messages = messageSets.length ? messageSets.at(-1)?.messages || [] : []
  }
  const filteredMessages = messages.filter(
    (m) =>
      m.type !== CHAT_MESSAGE_TYPE.DELETED &&
      m.type !== CHAT_MESSAGE_TYPE.SYSTEM &&
      !m.fs_message_deleted &&
      !isUserBlocked({ userId: m.user?.id, client })
  )
  return filteredMessages.length
    ? getMessageText({
        message: filteredMessages[filteredMessages.length - 1],
        t,
      }) || ''
    : ''
}

function getStartElement(
  item,
  hideMenuIcon,
  channel,
  isThread,
  multiSelectIsActive,
  selectedChannels,
  multiSelectDispatch,
  excludeUserId,
  t
) {
  let startElement
  if (multiSelectIsActive && !hideMenuIcon && !isThread) {
    startElement = (
      <Checkbox
        checked={selectedChannels.has(channel.cid)}
        onChange={() => multiSelectDispatch({ type: actionTypes.TOGGLE_CHANNEL_SELECTION, cid: item.cid })}
        onClick={(e) => e.stopPropagation()}
      />
    )
  } else if (isChannelMuted(channel)) {
    startElement = <ListItem.Icon Icon={NoticeMute} aria-label={t('chat.muted.aria-label', 'Muted')} />
  } else if (isPublicChannel(channel)) {
    startElement = <ListItem.Icon Icon={PersonGroup} />
  } else if (isVendorChannel(channel)) {
    startElement = <ListItem.Avatar src={channel?.data?.image} size="md" />
  } else if (isRootsTechChannel(channel)) {
    startElement = <ListItem.Icon Icon={LogoRootstech} />
  } else if (isSessionChannel(channel)) {
    startElement = <ListItem.Icon Icon={ThingPresentation} />
  } else if (isSupportChannel(channel)) {
    startElement = <ListItem.Icon Icon={AUAIconButton} />
  } else if (isHelperConnectChannel(channel)) {
    startElement = <ListItem.Icon Icon={LogoFamilysearch} background={colors.green30} color={colors.gray00} size="xs" />
  } else {
    startElement = getStreamChannelAvatar({
      channel,
      isInList: true,
      excludeUserId,
      size: 'md',
    })
  }
  return startElement
}

function getEndElement(
  item,
  channelMenuOverlay,
  onChannelMenuSelect,
  isHovering,
  isFocused,
  isSelected,
  isThread,
  showHoverMenu,
  currentChannelMenuOpen,
  setCurrentChannelMenuOpen,
  messagingChatLeftPanelRedesignIsOn,
  t
) {
  /*
    (as of May 2024)
    item.state.last_message_at updates during the Stream session
    item.data.last_message_at only updates after a refresh

    We will evaluate which timestamp is latest, so it displays and sorts correctly
  */
  const stateTimestamp = new Date(item?.state?.last_message_at)?.getTime()
  const dataTimestamp = new Date(item?.data?.last_message_at)?.getTime()
  const lastMessageDate = isThread ? item?.state?.getLatestValue()?.updatedAt : Math.max(stateTimestamp, dataTimestamp)

  let endElement
  if ((isFocused || isHovering || currentChannelMenuOpen || isSelected) && showHoverMenu) {
    endElement = (
      <ListItem.IconButton
        Icon={MenuMore}
        {...(channelMenuOverlay?.menuButtonProps || {})}
        aria-label={t('chat.menu.aria-label', 'Chat Menu')}
        onClick={(e) => {
          channelMenuOverlay?.menuButtonProps?.onClick?.(e)
          onChannelMenuSelect(item)
          setCurrentChannelMenuOpen(true)
        }}
      />
    )
  } else if (isThread && messagingChatLeftPanelRedesignIsOn) {
    endElement = <ListItem.Icon Icon={ContentReply} color={colors.gray30} />
  } else {
    endElement = <ListItem.MetaText text={formatChatTimestamp(lastMessageDate)} />
  }
  return endElement
}

export default function ChatChannelListItem({
  item,
  hideMenuIcon,
  lastElementRef,
  onItemSelect,
  channelMenuOverlay,
  onChannelMenuSelect,
  previousChatCid,
  isInUnreadList,
}) {
  const isThread = Boolean(item?.isStreamThread)
  const [t] = useTranslation()
  const { client, channels } = useChatState()
  const { multiSelectIsActive, selectedChannels } = useChatMultiSelectState()
  const multiSelectDispatch = useChatMultiSelectDispatch()
  const params = useParams()
  const channel = isThread ? channels.find((c) => c.cid === item?.channel?.cid) : item
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()

  const isSelected =
    cidMatchesChannel({ cid: params?.cid, channel: item }) || cidMatchesChannel({ cid: previousChatCid, channel: item })
  const excludeUserId = client?.userID

  const isUnread = !!getChannelUnreadCount({ channel: isThread ? item : channel })

  const participantCount = isThread
    ? item?.state?.getLatestValue()?.participants?.length
    : item?.data?.member_count || 0

  const shouldShowParticipantCount = !isDirectChannel(item) || participantCount > 2
  const { participantCountMessage } = shouldShowParticipantCount
    ? getChatGroupParticipantCountDescription(participantCount)
    : {}

  const lastMessage = getLastDisplayMessageForChannel({
    channel: item,
    client,
    t,
    isThread,
  })

  // If selected and not currently visible, scroll into view
  const listItemRef = useRef()

  useEffect(() => {
    if (isSelected && listItemRef.current && !isInUnreadList) {
      const scrollIntervalId = scrollChannelListItemIntoView(listItemRef)
      return () => {
        clearInterval(scrollIntervalId)
      }
    }
    return () => {}
  }, [isSelected, isInUnreadList])

  const [isHovering, setIsHovering] = useState(false)
  const [isFocused, setIsFocused] = useState(false)
  const isEmphasized = !hideMenuIcon && isUnread
  const Wrapper = isEmphasized ? UnreadWrapper : ListItemWrapper
  const canHover = window.matchMedia('(any-hover: hover)').matches
  const showHoverMenu = !hideMenuIcon && !isThread && canHover
  // This is to keep track of the current listItem's channel menu state so we can avoid unmounting the menu icon button until the menu anchored to it is closed.
  const [currentChannelMenuOpen, setCurrentChannelMenuOpen] = useState(false)
  const { isOpen, transitioning } = channelMenuOverlay || {}
  useEffect(() => {
    if (!isOpen && !transitioning) {
      setCurrentChannelMenuOpen(false)
    }
  }, [isOpen, transitioning])
  const wrapperProps = showHoverMenu
    ? {
        onMouseEnter: () => setIsHovering(true),
        onMouseLeave: () => setIsHovering(false),
        onFocusCapture: () => setIsFocused(true),
        onBlurCapture: (e) => {
          // mark the element as still focused until it leaves the listItem and all its children
          // This way screen reader users can access the hover menu when tabbing through
          // (e.relatedTarget is the element that the focus is moving to)
          const nextFocused = e.relatedTarget
          const stillInside = e.currentTarget.contains(nextFocused)
          if (!stillInside) {
            setIsFocused(false)
          }
        },
      }
    : {}
  const channelName = getChannelName({
    channel,
    excludeUserId,
  })
  const startElement = getStartElement(
    item,
    hideMenuIcon,
    channel,
    isThread,
    multiSelectIsActive,
    selectedChannels,
    multiSelectDispatch,
    excludeUserId,
    t
  )
  const endElement = getEndElement(
    item,
    channelMenuOverlay,
    onChannelMenuSelect,
    isHovering,
    isFocused,
    isSelected,
    isThread,
    showHoverMenu,
    currentChannelMenuOpen,
    setCurrentChannelMenuOpen,
    messagingChatLeftPanelRedesignIsOn,
    t
  )

  return (
    <Wrapper {...wrapperProps}>
      <ListItem
        // These refs don’t conflict. lastElementRef is only used in the browse group overlay, where listItemRef (for scrolling into view) isn’t needed
        ref={lastElementRef || listItemRef}
        as="div"
        dense={!messagingChatLeftPanelRedesignIsOn}
        data-testid="chat-item"
        // This is needed by performance QA to uniquely identify channel list items
        data-channelid={isThread ? item?.id : item.cid}
        emphasized={isEmphasized}
        selected={isSelected}
        startElement={startElement}
        id={isSelected ? 'active-chat-listitem' : undefined}
        primaryText={
          <Ellipsis>
            {isUnread && <VisuallyHidden>{t('chat.unread.label', 'Unread')}</VisuallyHidden>} {channelName}
          </Ellipsis>
        }
        secondaryText={<SecondaryText lastMessage={lastMessage} participantCount={participantCountMessage} />}
        endElement={endElement}
        onClick={() => onItemSelect(channel, null, isThread ? item?.id : null)}
      />
    </Wrapper>
  )
}

function UnreadWrapper(props) {
  // increases the contrast of unread messages in dark mode
  return (
    <li className={`${listItemResetCss} ${listItemUnreadDotCss}`} data-testid="unread-listItem-wrapper">
      <BillboardText primaryColor={colors.transparent.gray100} {...props} />
    </li>
  )
}

function isElementMostlyVisible(element, container) {
  const { bottom, height, top } = element.getBoundingClientRect()
  const containerRect = container.getBoundingClientRect()

  return top <= containerRect.top ? containerRect.top - top <= height / 2 : bottom - containerRect.bottom <= height / 2
}

export function scrollChannelListItemIntoView(elementRef) {
  let intervalId
  const scrollZone = document.getElementById('left-content-scroll-zone')
  if (elementRef.current && scrollZone && !isElementMostlyVisible(elementRef.current, scrollZone)) {
    elementRef.current.scrollIntoView?.({ behavior: 'smooth', block: 'center' })
    // In case the section needed to expand, scroll again after that. Smooth scrolling is flaky in this case.
    const expanderAnimationDelay = 500
    let attemptsLeft = 5
    intervalId = setInterval(() => {
      if (attemptsLeft === 0 || isElementMostlyVisible(elementRef.current, scrollZone)) {
        clearInterval(intervalId)
      } else {
        attemptsLeft--
        elementRef.current.scrollIntoView?.({ block: 'center' })
      }
    }, expanderAnimationDelay)
  }
  return intervalId
}
